fn make_advice_wrapper_after(original: Value, advice: Value) -> Value {
    let args_name = "__emaxx-advice-after-args".to_string();
    let original_name = "__emaxx-advice-after-original".to_string();
    let advice_name = "__emaxx-advice-after-function".to_string();
    Value::Lambda(
        vec!["&rest".into(), args_name.clone()],
        vec![Value::list([
            Value::Symbol("emaxx-apply-after-advice".into()),
            Value::Symbol(original_name.clone()),
            Value::Symbol(advice_name.clone()),
            Value::Symbol(args_name),
        ])],
        shared_env(vec![vec![(original_name, original), (advice_name, advice)]]),
    )
}

fn make_advice_wrapper_around(original: Value, advice: Value) -> Value {
    let args_name = "__emaxx-advice-around-args".to_string();
    let original_name = "__emaxx-advice-around-original".to_string();
    let advice_name = "__emaxx-advice-around-function".to_string();
    Value::Lambda(
        vec!["&rest".into(), args_name.clone()],
        vec![Value::list([
            Value::Symbol("emaxx-apply-around-advice".into()),
            Value::Symbol(original_name.clone()),
            Value::Symbol(advice_name.clone()),
            Value::Symbol(args_name),
        ])],
        shared_env(vec![vec![(original_name, original), (advice_name, advice)]]),
    )
}

#[derive(Clone)]
struct EieioSlotSpec {
    name: String,
    initargs: Vec<String>,
    initform: Value,
}

fn eieio_slot_specs(
    interp: &Interpreter,
    class_name: &str,
) -> Result<Vec<EieioSlotSpec>, LispError> {
    let mut slots = Vec::new();
    if let Some(parents) = interp.get_symbol_property(class_name, "emaxx-class-parents")
        && let Ok(parent_values) = parents.to_vec()
    {
        for parent in parent_values {
            if let Ok(parent_name) = parent.as_symbol() {
                slots.extend(eieio_slot_specs(interp, parent_name)?);
            }
        }
    }

    let Some(raw_slots) = interp.get_symbol_property(class_name, "emaxx-class-slots") else {
        return Ok(slots);
    };
    for raw_slot in raw_slots.to_vec()? {
        let parts = raw_slot.to_vec()?;
        let Some(slot_name) = parts
            .first()
            .and_then(|value| value.as_symbol().ok())
            .map(str::to_string)
        else {
            continue;
        };
        let mut initargs = Vec::new();
        let mut initform = Value::Nil;
        let mut index = 1usize;
        while index + 1 < parts.len() {
            let Some(keyword) = parts[index].as_symbol().ok() else {
                index += 1;
                continue;
            };
            match keyword {
                ":initarg" => {
                    if let Ok(initarg) = parts[index + 1].as_symbol() {
                        initargs.push(initarg.to_string());
                    }
                }
                ":initform" => initform = parts[index + 1].clone(),
                _ => {}
            }
            index += 2;
        }
        slots.push(EieioSlotSpec {
            name: slot_name,
            initargs,
            initform,
        });
    }
    Ok(slots)
}

fn eieio_slot_index(slots: &[EieioSlotSpec], slot_name: &str) -> Option<usize> {
    slots.iter().position(|slot| {
        slot.name == slot_name || slot.initargs.iter().any(|initarg| initarg == slot_name)
    })
}

fn make_eieio_instance(
    interp: &mut Interpreter,
    class_name: &str,
    initargs: &[Value],
    skip_obsolete_name: bool,
    env: &mut Env,
) -> Result<Value, LispError> {
    let slots = eieio_slot_specs(interp, class_name)?;
    let mut values = Vec::with_capacity(slots.len());
    for slot in &slots {
        values.push(interp.eval(&slot.initform, env)?);
    }

    let mut index = 0usize;
    if skip_obsolete_name
        && matches!(
            initargs.first(),
            Some(Value::Nil | Value::String(_) | Value::StringObject(_))
        )
    {
        index = 1;
    }

    while index + 1 < initargs.len() {
        let initarg = initargs[index].as_symbol()?;
        if !initarg.starts_with(':') {
            return Err(LispError::Signal(format!("Invalid initarg {initarg}")));
        }
        if let Some(slot_index) = slots
            .iter()
            .position(|slot| slot.initargs.iter().any(|candidate| candidate == initarg))
        {
            values[slot_index] = initargs[index + 1].clone();
        }
        index += 2;
    }

    Ok(interp.create_record(class_name, values))
}

fn eieio_slot_value(
    interp: &Interpreter,
    object: &Value,
    slot_name: &str,
) -> Result<Value, LispError> {
    let Value::Record(record_id) = object else {
        return Err(LispError::TypeError(
            "eieio-object".into(),
            object.type_name(),
        ));
    };
    let record = interp
        .find_record(*record_id)
        .ok_or_else(|| LispError::TypeError("record".into(), format!("record<{record_id}>")))?;
    let slots = eieio_slot_specs(interp, &record.type_name)?;
    let Some(slot_index) = eieio_slot_index(&slots, slot_name) else {
        return Err(LispError::Signal(format!("Invalid slot name: {slot_name}")));
    };
    Ok(record.slots.get(slot_index).cloned().unwrap_or(Value::Nil))
}

fn set_eieio_slot_value(
    interp: &mut Interpreter,
    object: &Value,
    slot_name: &str,
    value: Value,
) -> Result<Value, LispError> {
    let Value::Record(record_id) = object else {
        return Err(LispError::TypeError(
            "eieio-object".into(),
            object.type_name(),
        ));
    };
    let type_name = interp
        .find_record(*record_id)
        .ok_or_else(|| LispError::TypeError("record".into(), format!("record<{record_id}>")))?
        .type_name
        .clone();
    let slots = eieio_slot_specs(interp, &type_name)?;
    let Some(slot_index) = eieio_slot_index(&slots, slot_name) else {
        return Err(LispError::Signal(format!("Invalid slot name: {slot_name}")));
    };
    let record = interp
        .find_record_mut(*record_id)
        .ok_or_else(|| LispError::TypeError("record".into(), format!("record<{record_id}>")))?;
    if record.slots.len() <= slot_index {
        record.slots.resize(slot_index + 1, Value::Nil);
    }
    record.slots[slot_index] = value.clone();
    Ok(value)
}

fn activate_major_mode(interp: &mut Interpreter, mode: &str, mode_name: &str) {
    let buffer_id = interp.current_buffer_id();
    interp.set_buffer_local_value(buffer_id, "major-mode", Value::Symbol(mode.into()));
    interp.set_buffer_local_value(buffer_id, "mode-name", Value::String(mode_name.into()));
}

fn activate_c_family_mode(
    interp: &mut Interpreter,
    mode: &str,
    mode_name: &str,
) -> Result<Value, LispError> {
    if !interp.has_feature("newcomment") && interp.resolve_load_target("newcomment").is_some() {
        interp.load_target("newcomment")?;
    }
    let buffer_id = interp.current_buffer_id();
    activate_major_mode(interp, mode, mode_name);
    interp.set_buffer_local_value(buffer_id, "indent-tabs-mode", Value::T);
    interp.set_buffer_local_value(buffer_id, "comment-start", Value::String("/* ".into()));
    interp.set_buffer_local_value(buffer_id, "comment-end", Value::String(" */".into()));
    interp.set_buffer_local_value(
        buffer_id,
        "comment-start-skip",
        Value::String("\\(?://+\\|/\\*+\\)\\s *".into()),
    );
    interp.set_buffer_local_value(
        buffer_id,
        "comment-end-skip",
        Value::String("[ \t]*\\*+/".into()),
    );
    interp.set_buffer_local_value(buffer_id, "comment-use-syntax", Value::Nil);
    interp.set_buffer_local_value(buffer_id, "comment-style", Value::Symbol("indent".into()));
    interp.set_buffer_local_value(buffer_id, "comment-multi-line", Value::T);
    interp.set_buffer_local_value(buffer_id, "font-lock-mode", Value::T);
    interp.set_buffer_local_value(buffer_id, "jit-lock-mode", Value::T);
    if interp
        .buffer_local_value(buffer_id, "jit-lock-functions")
        .is_none()
    {
        interp.set_buffer_local_value(
            buffer_id,
            "jit-lock-functions",
            Value::list([Value::Symbol("ignore".into())]),
        );
    }
    interp.set_buffer_local_value(buffer_id, "font-lock-fontified", Value::T);
    Ok(Value::Nil)
}

const RAW_BYTE8_BASE: u32 = 0x3FFF00;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum CaseAction {
    Up,
    Down,
    Capitalize,
    UpcaseInitials,
}

fn is_raw_like_byte_char(code: u32) -> bool {
    matches!(code, 0x00CF | 0x00EF | 0x00FF)
}

fn raw_case_byte(key: u32) -> Option<u32> {
    if (RAW_BYTE8_BASE..=RAW_BYTE8_BASE + 0xFF).contains(&key) {
        Some(key - RAW_BYTE8_BASE)
    } else if (RAW_BYTE_REGEX_BASE..=RAW_BYTE_REGEX_BASE + 0xFF).contains(&key) {
        Some(key - RAW_BYTE_REGEX_BASE)
    } else {
        None
    }
}

fn normalize_case_key(key: u32) -> u32 {
    raw_case_byte(key).unwrap_or(key)
}

fn denormalize_case_key(template: u32, mapped: u32) -> u32 {
    if (RAW_BYTE8_BASE..=RAW_BYTE8_BASE + 0xFF).contains(&template) && mapped <= 0xFF {
        RAW_BYTE8_BASE + mapped
    } else if (RAW_BYTE_REGEX_BASE..=RAW_BYTE_REGEX_BASE + 0xFF).contains(&template)
        && mapped <= 0xFF
    {
        RAW_BYTE_REGEX_BASE + mapped
    } else {
        mapped
    }
}

fn alternate_case_key(key: u32) -> Option<u32> {
    if key <= 0xFF {
        Some(RAW_BYTE8_BASE + key)
    } else if (RAW_BYTE8_BASE..=RAW_BYTE8_BASE + 0xFF).contains(&key) {
        Some(key - RAW_BYTE8_BASE)
    } else if (RAW_BYTE_REGEX_BASE..=RAW_BYTE_REGEX_BASE + 0xFF).contains(&key) {
        Some(RAW_BYTE8_BASE + (key - RAW_BYTE_REGEX_BASE))
    } else {
        None
    }
}

fn raw_byte_regex_char(byte: u8) -> char {
    char::from_u32(RAW_BYTE_REGEX_BASE + byte as u32)
        .expect("raw byte regex marker is a valid private-use character")
}

fn raw_byte_from_regex_char(ch: char) -> Option<u8> {
    let code = ch as u32;
    if (RAW_BYTE_REGEX_BASE..=RAW_BYTE_REGEX_BASE + 0xFF).contains(&code) {
        Some((code - RAW_BYTE_REGEX_BASE) as u8)
    } else {
        None
    }
}

fn is_raw_byte_regex_char(ch: char) -> bool {
    raw_byte_from_regex_char(ch).is_some()
}

fn single_char_case_mapping(iter: impl Iterator<Item = char>, fallback: u32) -> u32 {
    let mut iter = iter;
    match (iter.next(), iter.next()) {
        (Some(mapped), None) => mapped as u32,
        _ => fallback,
    }
}

fn simple_upcase_char(code: u32) -> u32 {
    let code = normalize_case_key(code);
    match code {
        0x00DF => 0x1E9E,
        0x01C4..=0x01C6 => 0x01C4,
        0x03C2 | 0x03C3 => 0x03A3,
        0x2177 => 0x2167,
        _ if is_raw_like_byte_char(code) => code,
        _ => char::from_u32(code)
            .map(|ch| single_char_case_mapping(ch.to_uppercase(), code))
            .unwrap_or(code),
    }
}

fn simple_downcase_char(code: u32, final_sigma: bool) -> u32 {
    let code = normalize_case_key(code);
    match code {
        0x1E9E => 0x00DF,
        0x0130 => 0x0069,
        0x01C4 | 0x01C5 => 0x01C6,
        0x03A3 => {
            if final_sigma {
                0x03C2
            } else {
                0x03C3
            }
        }
        0x2167 => 0x2177,
        _ if is_raw_like_byte_char(code) => code,
        _ => char::from_u32(code)
            .map(|ch| single_char_case_mapping(ch.to_lowercase(), code))
            .unwrap_or(code),
    }
}

fn simple_titlecase_char(code: u32) -> u32 {
    let code = normalize_case_key(code);
    match code {
        0x01C4..=0x01C6 => 0x01C5,
        _ => simple_upcase_char(code),
    }
}

fn unicode_character_name(code: u32) -> Option<String> {
    char::from_u32(code)
        .and_then(unicode_name)
        .map(|name| name.to_string())
}

fn unicode_general_category_symbol(code: u32) -> Option<&'static str> {
    if (0xD800..=0xDFFF).contains(&code) {
        Some("Cs")
    } else {
        char::from_u32(code).map(|ch| get_general_category(ch).abbreviation())
    }
}

fn unicode_general_category_description(symbol: &str) -> Option<&'static str> {
    match symbol {
        "Lu" => Some("Letter, Uppercase"),
        "Ll" => Some("Letter, Lowercase"),
        "Lt" => Some("Letter, Titlecase"),
        "Lm" => Some("Letter, Modifier"),
        "Lo" => Some("Letter, Other"),
        "Mn" => Some("Mark, Nonspacing"),
        "Mc" => Some("Mark, Spacing Combining"),
        "Me" => Some("Mark, Enclosing"),
        "Nd" => Some("Number, Decimal Digit"),
        "Nl" => Some("Number, Letter"),
        "No" => Some("Number, Other"),
        "Pc" => Some("Punctuation, Connector"),
        "Pd" => Some("Punctuation, Dash"),
        "Ps" => Some("Punctuation, Open"),
        "Pe" => Some("Punctuation, Close"),
        "Pi" => Some("Punctuation, Initial quote"),
        "Pf" => Some("Punctuation, Final quote"),
        "Po" => Some("Punctuation, Other"),
        "Sm" => Some("Symbol, Math"),
        "Sc" => Some("Symbol, Currency"),
        "Sk" => Some("Symbol, Modifier"),
        "So" => Some("Symbol, Other"),
        "Zs" => Some("Separator, Space"),
        "Zl" => Some("Separator, Line"),
        "Zp" => Some("Separator, Paragraph"),
        "Cc" => Some("Other, Control"),
        "Cf" => Some("Other, Format"),
        "Cs" => Some("Other, Surrogate"),
        "Co" => Some("Other, Private Use"),
        "Cn" => Some("Other, Not Assigned"),
        _ => None,
    }
}

fn unicode_property_description(property: &str, value: &Value) -> Option<&'static str> {
    match property {
        "general-category" => match value {
            Value::Nil => Some("Unknown"),
            Value::Symbol(symbol) => unicode_general_category_description(symbol),
            _ => {
                string_like(value).and_then(|text| unicode_general_category_description(&text.text))
            }
        },
        _ => None,
    }
}

pub(crate) fn case_table_default_value(subtype: Option<&str>, key: u32) -> Option<Value> {
    let mapped = match subtype {
        Some("case-table") => simple_downcase_char(key, false),
        Some("case-table-up") => simple_upcase_char(key),
        _ => return None,
    };
    Some(Value::Integer(denormalize_case_key(key, mapped) as i64))
}

fn current_case_table_ids(interp: &mut Interpreter) -> Result<(u64, u64), LispError> {
    let down = interp.current_case_table_id();
    let up = match interp.char_table_extra_slot(down, 0) {
        Some(Value::CharTable(id)) => id,
        _ => down,
    };
    Ok((down, up))
}

fn explicit_case_table_mapping(interp: &Interpreter, table_id: u64, code: u32) -> Option<u32> {
    for candidate in [Some(code), alternate_case_key(code)].into_iter().flatten() {
        let Some(Value::Integer(mapped)) = interp.char_table_explicit_get(table_id, candidate)
        else {
            continue;
        };
        let mapped = u32::try_from(mapped).ok()?;
        return Some(normalize_case_key(mapped));
    }
    None
}

fn case_symbols_as_words_enabled(interp: &Interpreter, env: &Env) -> bool {
    interp
        .lookup_var("case-symbols-as-words", env)
        .is_some_and(|value| value.is_truthy())
}

fn case_word_char(interp: &Interpreter, ch: char, case_symbols_as_words: bool) -> bool {
    ch.is_alphanumeric()
        || (case_symbols_as_words && ch == '_')
        || interp.is_syntax_word_char(normalize_case_key(ch as u32))
}

fn full_upcase_string(interp: &Interpreter, up_table: u64, ch: char) -> String {
    let code = ch as u32;
    if let Some(mapped) = explicit_case_table_mapping(interp, up_table, code) {
        return char::from_u32(denormalize_case_key(code, mapped))
            .unwrap_or(ch)
            .to_string();
    }
    match code {
        _ if is_raw_like_byte_char(code) => ch.to_string(),
        _ => ch.to_uppercase().collect(),
    }
}

fn full_downcase_string(
    interp: &Interpreter,
    down_table: u64,
    ch: char,
    final_sigma: bool,
) -> String {
    let code = ch as u32;
    if let Some(mapped) = explicit_case_table_mapping(interp, down_table, code) {
        return char::from_u32(denormalize_case_key(code, mapped))
            .unwrap_or(ch)
            .to_string();
    }
    match code {
        0x03A3 => char::from_u32(simple_downcase_char(code, final_sigma))
            .unwrap_or(ch)
            .to_string(),
        _ if is_raw_like_byte_char(code) => ch.to_string(),
        _ => ch.to_lowercase().collect(),
    }
}

fn full_titlecase_string(interp: &Interpreter, up_table: u64, ch: char) -> String {
    let code = ch as u32;
    if let Some(mapped) = explicit_case_table_mapping(interp, up_table, code) {
        return char::from_u32(denormalize_case_key(code, mapped))
            .unwrap_or(ch)
            .to_string();
    }
    match code {
        0x00DF => "Ss".into(),
        0xFB01 => "Fi".into(),
        0x01C4..=0x01C6 => '\u{01C5}'.to_string(),
        _ if is_raw_like_byte_char(code) => ch.to_string(),
        _ => char::from_u32(denormalize_case_key(code, simple_titlecase_char(code)))
            .unwrap_or(ch)
            .to_string(),
    }
}

fn simple_case_char_for_action(
    interp: &Interpreter,
    down_table: u64,
    up_table: u64,
    code: u32,
    action: CaseAction,
) -> u32 {
    let mapped = match action {
        CaseAction::Up => explicit_case_table_mapping(interp, up_table, code)
            .unwrap_or_else(|| simple_upcase_char(code)),
        CaseAction::Down => explicit_case_table_mapping(interp, down_table, code)
            .unwrap_or_else(|| simple_downcase_char(code, false)),
        CaseAction::Capitalize | CaseAction::UpcaseInitials => {
            explicit_case_table_mapping(interp, up_table, code)
                .unwrap_or_else(|| simple_titlecase_char(code))
        }
    };
    denormalize_case_key(code, mapped)
}

fn casify_string(
    interp: &mut Interpreter,
    input: &str,
    action: CaseAction,
    env: &Env,
) -> Result<String, LispError> {
    let case_symbols_as_words = case_symbols_as_words_enabled(interp, env);
    let (down_table, up_table) = current_case_table_ids(interp)?;
    let chars: Vec<char> = input.chars().collect();
    let mut output = String::new();
    let mut in_word = false;
    for (idx, ch) in chars.iter().copied().enumerate() {
        let is_word = case_word_char(interp, ch, case_symbols_as_words);
        let next_is_word = chars
            .get(idx + 1)
            .copied()
            .is_some_and(|next| case_word_char(interp, next, case_symbols_as_words));
        let piece = match action {
            CaseAction::Up => full_upcase_string(interp, up_table, ch),
            CaseAction::Down => {
                full_downcase_string(interp, down_table, ch, in_word && !next_is_word)
            }
            CaseAction::Capitalize => {
                if is_word && !in_word {
                    full_titlecase_string(interp, up_table, ch)
                } else {
                    full_downcase_string(interp, down_table, ch, in_word && !next_is_word)
                }
            }
            CaseAction::UpcaseInitials => {
                if is_word && !in_word {
                    full_titlecase_string(interp, up_table, ch)
                } else {
                    ch.to_string()
                }
            }
        };
        output.push_str(&piece);
        in_word = is_word;
    }
    Ok(output)
}

fn casify_value(
    interp: &mut Interpreter,
    value: &Value,
    action: CaseAction,
    env: &Env,
) -> Result<Value, LispError> {
    if let Ok(integer) = value.as_integer() {
        let code = u32::try_from(integer)
            .map_err(|_| LispError::Signal(format!("Invalid character: {integer}")))?;
        let (down_table, up_table) = current_case_table_ids(interp)?;
        return Ok(Value::Integer(simple_case_char_for_action(
            interp, down_table, up_table, code, action,
        ) as i64));
    }
    let input = string_text(value)?;
    Ok(Value::String(casify_string(interp, &input, action, env)?))
}

fn replace_buffer_region_with_text(
    interp: &mut Interpreter,
    start: usize,
    end: usize,
    text: &str,
) -> Result<usize, LispError> {
    interp.buffer.goto_char(start);
    interp
        .buffer
        .delete_region(start, end)
        .map_err(|error| LispError::Signal(error.to_string()))?;
    interp.buffer.insert(text);
    Ok(start + text.chars().count())
}

fn casify_buffer_region(
    interp: &mut Interpreter,
    start: usize,
    end: usize,
    action: CaseAction,
    env: &Env,
) -> Result<usize, LispError> {
    let lo = start.min(end);
    let hi = start.max(end);
    if lo >= hi {
        return Ok(hi);
    }
    let text = interp
        .buffer
        .buffer_substring(lo, hi)
        .map_err(|error| LispError::Signal(error.to_string()))?;
    let mapped = casify_string(interp, &text, action, env)?;
    replace_buffer_region_with_text(interp, lo, hi, &mapped)
}

fn parse_region_bound(value: &Value) -> Result<(usize, usize), LispError> {
    let Some((start, end)) = value.cons_values() else {
        return Err(LispError::Signal("Invalid region bounds".into()));
    };
    let start = start
        .as_integer()
        .map_err(|_| LispError::Signal("Invalid region bounds".into()))?;
    let end = end
        .as_integer()
        .map_err(|_| LispError::Signal("Invalid region bounds".into()))?;
    if start < 0 || end < 0 {
        return Err(LispError::Signal("Invalid region bounds".into()));
    }
    Ok((start as usize, end as usize))
}

fn parse_region_bounds(value: &Value) -> Result<Vec<(usize, usize)>, LispError> {
    let mut cursor = value.clone();
    let mut bounds = Vec::new();
    for _ in 0..1024 {
        match cursor {
            Value::Nil => return Ok(bounds),
            Value::Cons(car, cdr) => {
                bounds.push(parse_region_bound(&car.borrow())?);
                cursor = cdr.borrow().clone();
            }
            _ => return Err(LispError::Signal("Invalid region bounds".into())),
        }
    }
    Err(LispError::Signal("Invalid region bounds".into()))
}

fn case_word_region(interp: &Interpreter, point: usize, count: i64, env: &Env) -> (usize, usize) {
    let case_symbols_as_words = case_symbols_as_words_enabled(interp, env);
    let is_word = |ch: char| case_word_char(interp, ch, case_symbols_as_words);
    let mut cursor = point;
    let mut remaining = count.unsigned_abs();
    if count >= 0 {
        while remaining > 0 {
            while let Some(ch) = interp.buffer.char_at(cursor) {
                if is_word(ch) {
                    break;
                }
                cursor += 1;
            }
            while let Some(ch) = interp.buffer.char_at(cursor) {
                if !is_word(ch) {
                    break;
                }
                cursor += 1;
            }
            remaining -= 1;
        }
        (point, cursor)
    } else {
        while remaining > 0 {
            while cursor > interp.buffer.point_min() {
                let Some(ch) = interp.buffer.char_at(cursor - 1) else {
                    break;
                };
                if is_word(ch) {
                    break;
                }
                cursor -= 1;
            }
            while cursor > interp.buffer.point_min() {
                let Some(ch) = interp.buffer.char_at(cursor - 1) else {
                    break;
                };
                if !is_word(ch) {
                    break;
                }
                cursor -= 1;
            }
            remaining -= 1;
        }
        (cursor, point)
    }
}

